{code}
note: the binary data length has to be larger than the defined gridfs file chunk size

 # in client side, issue the following call
{code:c}mongoc_gridfs_file_readv(...)
{code}
 # it will cause an *BSON_ASSERT (len <= chunk_size);* since the len of this page is larger than the chunk_size
{code:c}mongoc_gridfs_file_page_t *
_mongoc_gridfs_file_page_new (const uint8_t *data,
                              uint32_t len,
                              uint32_t chunk_size)
{
   mongoc_gridfs_file_page_t *page;

   ENTRY;

   BSON_ASSERT (data);
   BSON_ASSERT (len <= chunk_size);

   page = (mongoc_gridfs_file_page_t *) bson_malloc0 (sizeof *page);

   page->chunk_size = chunk_size;
   page->read_buf = data;
   page->len = len;

   RETURN (page);
